const inputData = $input.first().json;

// Normalize input fields
function normalize(v) {
  return String(v ?? '').trim();
}

function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return '';
}

const mode = normalize(inputData.mode); // 'scratch' or 'theses'
const articleType = normalize(inputData.articleType); // 'thought_leadership', 'howto', 'pr_news'
const speakerId = normalize(inputData.speakerId);
const topic = normalize(inputData.topic);
const description = normalize(inputData.description);
const theses = inputData.theses; // Array of strings for theses mode
const jobId = normalize(inputData.jobId);
const callbackUrl = normalize(inputData.callbackUrl);

// Validation
const missingFields = [];
if (!mode) missingFields.push('mode (scratch/theses)');
if (!articleType) missingFields.push('articleType (thought_leadership/howto/pr_news)');
if (!speakerId) missingFields.push('speakerId');
if (mode === 'scratch' && !topic) missingFields.push('topic');
if (mode === 'scratch' && !description) missingFields.push('description');
if (mode === 'theses' && (!theses || !Array.isArray(theses) || theses.length === 0)) missingFields.push('theses (array of strings)');
if (!jobId) missingFields.push('jobId');

// Validate article type
const validArticleTypes = ['thought_leadership', 'howto', 'pr_news'];
if (articleType && !validArticleTypes.includes(articleType)) {
  missingFields.push('articleType must be one of: thought_leadership, howto, pr_news');
}

// Validate mode
const validModes = ['scratch', 'theses'];
if (mode && !validModes.includes(mode)) {
  missingFields.push('mode must be one of: scratch, theses');
}

return [{
  json: {
    ...inputData,
    mode,
    articleType,
    speakerId,
    topic,
    description,
    theses: mode === 'theses' ? theses : [],
    jobId,
    callbackUrl,
    isValid: missingFields.length === 0,
    missingFields,
    timestamp: new Date().toISOString(),
  },
}];

// Fallback profile if GitHub fetch fails
const speakerId = $input.first().json.speakerId;

const fallbackProfiles = {
  maria_arkhangelskaya: {
    name_ru: "Мария Архангельская",
    title_ru: "Генеральный директор и управляющий партнёр",
    company: "DDVB",
    voice_guidelines: "Экспертный, но не менторский. Конкретные примеры. Живые глаголы."
  },
  default: {
    name_ru: "Эксперт DDVB",
    title_ru: "Специалист",
    company: "DDVB",
    voice_guidelines: "Экспертный тон. Конкретика. Живой язык."
  }
};

const profileData = $input.first().json.profileData;
const profile = profileData ? JSON.parse(profileData) : fallbackProfiles[speakerId] || fallbackProfiles.default;

return [{
  json: {
    ...$input.first().json,
    profile,
    speakerName: profile.name_ru,
    speakerTitle: profile.title_ru,
    speakerCompany: profile.company,
    speakerVoiceGuidelines: profile.voice_guidelines,
  },
}];

// Build 4 parallel research queries for Scratch mode
const topic = $input.first().json.topic;
const description = $input.first().json.description;
const articleType = $input.first().json.articleType;

// Context prefixes for Russian market
const ruContext = "Россия, российский рынок: ";

// Four research streams
const queries = [
  // Stream 1: Industry context and trends
  `${ruContext}${topic} — отраслевые тренды, состояние рынка, ключевые игроки`,
  // Stream 2: Expert opinions and analytics
  `${ruContext}${topic} — экспертные мнения, аналитика, прогнозы`,
  // Stream 3: Case studies and examples
  `${ruContext}${topic} — практические примеры, кейсы, успешные проекты`,
  // Stream 4: Statistics and data
  `${ruContext}${topic} — статистика, метрики, исследования`
];

return queries.map((q, i) => ({
  json: {
    query: q,
    streamId: i + 1,
    topic,
    description,
    articleType
  }
}));

// Merge 4 research streams for Scratch mode
const items = $input.all();

// Combine all research into one structure
let mergedContent = "";
let allSources = [];

for (const item of items) {
  const json = item.json;
  mergedContent += `\n## Поток ${json.streamId}: ${json.query}\n`;
  mergedContent += json.content || "";

  // Extract sources if available
  if (json.sources) {
    allSources = allSources.concat(json.sources);
  }
}

return [{
  json: {
    ...$input.first().json,
    researchContent: mergedContent,
    researchSources: allSources,
    researchMode: "scratch",
    streamCount: items.length
  }
}];

// Prepare thesis research for Theses mode
const theses = $input.first().json.theses || [];
const topic = $input.first().json.topic || $input.first().json.description;
const ruContext = "Россия, российский рынок: ";

// For each thesis, create a research item
return theses.map((thesis, i) => ({
  json: {
    thesis: thesis,
    thesisIndex: i + 1,
    totalTheses: theses.length,
    topic,
    query: `${ruContext}${topic} — ${thesis}`
  }
}));

// Merge thesis research results
const items = $input.all();

let mergedContent = "";
let allSources = [];

for (const item of items) {
  const json = item.json;
  mergedContent += `\n### Тезис ${json.thesisIndex}: ${json.thesis}\n`;
  mergedContent += json.content || "";

  if (json.sources) {
    allSources = allSources.concat(json.sources);
  }
}

return [{
  json: {
    ...$input.first().json,
    researchContent: mergedContent,
    researchSources: allSources,
    researchMode: "theses",
    thesisCount: items.length
  }
}];

// Build writer prompt based on article type
const articleType = $input.first().json.articleType;
const topic = $input.first().json.topic;
const description = $input.first().json.description;
const researchContent = $input.first().json.researchContent;
const speakerName = $input.first().json.speakerName;
const speakerTitle = $input.first().json.speakerTitle;
const speakerCompany = $input.first().json.speakerCompany;
const speakerVoiceGuidelines = $input.first().json.speakerVoiceGuidelines;

// Load prompt template based on type
const promptTemplates = {
  thought_leadership: `Ты — экспертный автор брендингового агентства DDVB. Напиши Thought Leadership статью.

## Тема
${topic}

## Описание
${description}

## Результат исследования
${researchContent}

## Профиль спикера
Имя: ${speakerName}
Должность: ${speakerTitle}
Компания: ${speakerCompany}

## Voice Guidelines
${speakerVoiceGuidelines}

## Требования
- Объём: 1800-2200 слов
- Структура: Лид → Контекст → Экспертный взгляд → Примеры → Вывод
- Используй заголовки H2
- Экспертный, но не менторский тон
- Конкретные примеры и цифры`,

  howto: `Ты — экспертный автор брендингового агентства DDVB. Напиши How-to статью (практическое руководство).

## Тема
${topic}

## Описание
${description}

## Результат исследования
${researchContent}

## Профиль спикера
Имя: ${speakerName}
Должность: ${speakerTitle}
Компания: ${speakerCompany}

## Voice Guidelines
${speakerVoiceGuidelines}

## Требования
- Объём: 1500-2000 слов
- Структура: Введение → Понимание проблемы → Пошаговое руководство → Примеры → Заключение
- Используй заголовки H2 и нумерованные списки
- Практический, конкретный тон
- Обращение «ты» к читателю`,

  pr_news: `Ты — PR-автор брендингового агентства DDVB. Напиши PR/новостную статью.

## Тема
${topic}

## Описание
${description}

## Результат исследования
${researchContent}

## Профиль спикера
Имя: ${speakerName}
Должность: ${speakerTitle}
Компания: ${speakerCompany}

## Требования
- Объём: 800-1200 слов
- Структура: Заголовок → Лид → Основная часть → Справка о компании → Контакты
- Новостной, информативный тон
- Факты и цифры на первом месте
- Включи прямую цитату спикера`
};

const systemPrompt = promptTemplates[articleType] || promptTemplates.thought_leadership;

return [{
  json: {
    ...$input.first().json,
    writerSystemPrompt: systemPrompt,
    articleType
  }
}];

// Extract article and calculate stats
const article = $input.first().json.content || $input.first().json.article || "";
const charCount = article.length;
const wordCount = article.split(/\s+/).filter(w => w.length > 0).length;

return [{
  json: {
    ...$input.first().json,
    article,
    charCount,
    wordCount,
    timestamp: new Date().toISOString()
  }
}];

// Error response for missing fields
const missingFields = $input.first().json.missingFields || [];

return [{
  json: {
    success: false,
    error: "Missing required fields",
    details: missingFields,
    message: `Не хватает обязательных полей: ${missingFields.join(', ')}`
  }
}];

// Build error callback payload
const jobId = $input.first().json.jobId;
const callbackUrl = $input.first().json.callbackUrl;
const errorMessage = $input.first().json.error?.message || "Unknown error";
const errorStage = $input.first().json.error?.stage || "unknown";

if (!jobId || !callbackUrl) {
  return [{
    json: {
      success: false,
      message: "No jobId or callbackUrl to notify"
    }
  }];
}

return [{
  json: {
    jobId,
    callbackUrl,
    errorMessage,
    errorStage,
    timestamp: new Date().toISOString()
  }
}];
